describe("Request class",()=>{it("should construct a new Request object with the provided URL",()=>{let e="https://example.com",t=new Request(e);expect(t.url).toEqual(e)}),it("should set the method to GET by default",()=>{let e=new Request("https://example.com");expect(e.method).toEqual("GET")}),it("should set the mode to cors by default",()=>{let e=new Request("https://example.com");expect(e.mode).toEqual("cors")}),it("should set the cache to no-store by default",()=>{let e=new Request("https://example.com");expect(e.cache).toEqual("no-store")}),it("should set the bodyUsed to false by default",()=>{let e=new Request("https://example.com");expect(e.bodyUsed).toBeFalsy()}),it("should set the method to the provided value",()=>{let e="POST",t=new Request("https://example.com",{method:e});expect(t.method).toEqual(e)}),it("should set the headers to an empty object by default",()=>{let e=new Request("https://example.com"),t=new Headers;expect(e.headers.entries()).toEqual(t.entries())}),it("should set the headers to the provided value",()=>{let e={"Content-Type":"application/json"},t=new Headers(e),o=new Request("https://example.com",{headers:e});expect(o.headers).toStrictEqual(t)}),it("should set the body to null by default",()=>{let e=new Request("https://example.com");expect(e.body).toEqual(null)}),it("should set the body to the provided value",()=>{let e="hello world!",t=new Request("https://example.com",{body:e,method:"POST"});expect(t.body).toStrictEqual(e),expect(t.bodyUsed).toBeFalsy()}),it("should accept another request object as argument",()=>{let e=new Request("https://example.com",{headers:{From:"webmaster@example.org"}});expect(e.headers.get("From")).toEqual("webmaster@example.org");let t=new Request(e,{headers:{From:"developer@example.org"}});expect(t.url).toEqual("https://example.com"),expect(t.headers.get("From")).toEqual("developer@example.org")}),it("should accept a signal as an option",()=>{let e=new AbortController,t=new Request("http://localhost",{signal:e.signal});expect(t.signal).toEqual(e.signal)}),it("should accept null or undefined as signal options",()=>{let e=new Request("http://localhost",{signal:null});expect(e.signal).toBeUndefined();let t=new Request("http://localhost",{signal:void 0});expect(t.signal).toBeUndefined()}),it("should fail if the signal option is not an object",()=>{expect(()=>{new Request("http://localhost",{signal:"type error"})}).toThrow(/property is not an AbortSignal/)}),it("should fail if the signal option is not an valid object",()=>{expect(()=>{new Request("http://localhost",{signal:new Request("http://localhost")})}).toThrow(/property is not an AbortSignal/)}),it("should return the provided body via text() and set bodyUsed to true",async()=>{let e="Hello, world!",t=new Request("http://localhost",{body:e,method:"POST"});expect(t.bodyUsed).toBeFalsy(),expect(await t.text()).toStrictEqual(e),expect(t.bodyUsed).toBeTruthy()}),it("should set the body to a JSON object if a JSON object is provided",async()=>{let e={key:"value"},t=new Request("http://localhost",{body:JSON.stringify(e),method:"POST"});expect(t.bodyUsed).toBeFalsy(),expect(await t.json()).toStrictEqual(e),expect(t.bodyUsed).toBeTruthy()}),it("should set the body to a bytes object if a bytes object is provided",async()=>{let e=new Uint8Array([1,2,3]),t=new Request("http://localhost",{body:e,method:"POST"});expect(t.bodyUsed).toBeFalsy(),expect(await t.bytes()).toStrictEqual(e),expect(t.bodyUsed).toBeTruthy()}),it("should set the body to a Blob if a Blob is provided",async()=>{let e=new Blob(["Hello, world!"],{type:"text/plain"}),t=new Request("http://localhost",{body:e,method:"POST"});expect(t.bodyUsed).toBeFalsy();let o=await t.blob();expect(t.bodyUsed).toBeTruthy(),expect(o.size).toEqual(e.size),expect(o.type).toEqual("text/plain")}),it("should set the body to a Blob if Blob and content-type are provided",async()=>{let e=new Blob(["Hello, world!"],{type:"text/html"}),o=await new Request("http://localhost",{body:e,method:"POST",headers:{"content-type":"text/plain"}}).blob();expect(o.size).toEqual(e.size),expect(o.type).toEqual("text/plain")}),it("should ignore request options which are not an object",async()=>{let e=new Request("http://localhost",void 0);expect(e instanceof Request).toBeTruthy()})});
